"use client";

import React, { createContext, useContext, useState, useEffect } from 'react';

interface User {
  name: string;
  email?: string;
}

interface AuthContextType {
  user: User | null;
  login: (name: string, email?: string) => void; // Adicionei email aqui
  logout: () => void;
  isLoading: boolean;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export function AuthProvider({ children }: { children: React.ReactNode }) {
  const [user, setUser] = useState<User | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    // Tenta recuperar os dados completos do objeto usuário
    const savedUser = localStorage.getItem("nani_user");
    if (savedUser) {
      try {
        setUser(JSON.parse(savedUser));
      } catch (e) {
        localStorage.removeItem("nani_user");
      }
    }
    setIsLoading(false);
  }, []);

  const login = (name: string, email?: string) => {
    const userData = { name, email };
    setUser(userData);
    // Guardamos o objeto inteiro como string para não perder o email
    localStorage.setItem("nani_user", JSON.stringify(userData));
  };

  const logout = () => {
    setUser(null);
    localStorage.removeItem("nani_user");
    // Removi o window.location.href para evitar loops de recarregamento
    // Deixamos a página que chama o logout decidir para onde ir
  };

  return (
    <AuthContext.Provider value={{ user, login, logout, isLoading }}>
      {children}
    </AuthContext.Provider>
  );
}

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error("useAuth deve ser usado dentro de um AuthProvider");
  }
  return context;
};